        .init(es: "Cada run te acerca un paso a quien quieres ser.", en: "Every run brings you one step closer to who you want to be."),
        .init(es: "Hoy el sillón no gana. Tú sí.", en: "Today the couch doesn't win. You do."),
        .init(es: "Corre. La versión más fuerte de ti ya está calentando.", en: "Run. Your strongest self is already warming up."),
        .init(es: "Tu pacepal sabe cuándo corriste. Y cuándo no.", en: "Your pacepal knows when you ran. And when you didn't."),
